  <div style={{background:'#080B0F', minHeight:'100vh', display:'flex', 
    alignItems:'center', justifyContent:'center'}}>
    <h1 style={{color:'#FF4D4D', fontFamily:'sans-serif'}}>⚡ FixIt Admin Works!</h1>
  </div>
);
